// 解析 webhook 輸入：{ lat, lon, date, event_id?, event_name? }
// 輸出 lat_round / lon_round（0.1° 格網）+ target_date
const body = $input.first().json.body ?? $input.first().json;

const lat = Number(body.lat);
const lon = Number(body.lon);
const dateStr = String(body.date || '').slice(0, 10); // YYYY-MM-DD

if (!Number.isFinite(lat) || !Number.isFinite(lon)) {
  throw new Error('lat/lon 必填且需為數字');
}
if (!/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) {
  throw new Error('date 必填，格式 YYYY-MM-DD');
}

const lat_round = Math.round(lat * 10) / 10;
const lon_round = Math.round(lon * 10) / 10;

return [{
  json: {
    lat, lon,
    lat_round, lon_round,
    target_date: dateStr,
    event_id:   body.event_id ?? null,
    event_name: body.event_name ?? null,
  }
}];

// 聚合：把 Check Cache 的 N 筆 row 收成單一 item + has_cache 旗標
// 過濾 alwaysOutputData 注入的空 item（沒 forecast_time 就不算 cache）
const rows = $input.all()
  .map(i => i.json)
  .filter(r => r && r.forecast_time);
const meta = $('Normalize Input').first().json;
return [{
  json: {
    ...meta,
    cached_rows: rows,
    has_cache: rows.length > 0,
  }
}];

// 命中快取：從 Aggregate Cache 拿 cached_rows + meta
const meta = $json;
const rows = meta.cached_rows || [];

const pops   = rows.map(r => Number(r.pop ?? 0));
const winds  = rows.map(r => Number(r.wind_speed ?? 0));
const temps  = rows.map(r => Number(r.temp ?? 0));
const feels  = rows.map(r => Number(r.feels_like ?? 0));

const max_pop  = pops.length  ? Math.max(...pops)  : 0;
const max_wind = winds.length ? Math.max(...winds) : 0;
const max_temp = temps.length ? Math.max(...temps) : 0;
const min_temp = temps.length ? Math.min(...temps) : 0;
const max_feels= feels.length ? Math.max(...feels) : 0;
const avg_temp = temps.length ? +(temps.reduce((a,b)=>a+b,0) / temps.length).toFixed(1) : null;

const tags = [];
if (max_pop  >= 0.6) tags.push('heavy_rain_risk');
if (max_wind >= 10)  tags.push('strong_wind');
else if (max_wind >= 8) tags.push('windy');
if (max_temp >= 35)  tags.push('hot');
if (max_feels >= 38) tags.push('heat_stress');
if (min_temp <= 10)  tags.push('cold');

return [{
  json: {
    cached: true,
    event_id: meta.event_id,
    event_name: meta.event_name,
    lat_round: meta.lat_round,
    lon_round: meta.lon_round,
    date: meta.target_date,
    forecasts: rows,
    summary: {
      slots: rows.length,
      max_pop, max_wind, max_temp, min_temp, max_feels, avg_temp,
      alert_tags: tags,
    }
  }
}];

// 直接組好完整 SQL（多行 VALUES inline），避開 queryReplacement 逗號切割問題
const meta = $('Normalize Input').first().json;
const fc = $input.first().json.list || [];

const esc = (s) => String(s).replace(/'/g, "''");
const num = (v) => (v === null || v === undefined || Number.isNaN(v)) ? 'NULL' : v;
const txt = (v) => (v === null || v === undefined) ? 'NULL' : `'${esc(v)}'`;

const day_forecasts = [];
const valueLines = [];

for (const f of fc) {
  const ft = new Date(f.dt * 1000).toISOString();
  const row = {
    forecast_time: ft,
    temp:         f.main?.temp ?? null,
    feels_like:   f.main?.feels_like ?? null,
    humidity:     f.main?.humidity ?? null,
    pop:          f.pop ?? 0,
    rain_3h:      f.rain?.['3h'] ?? 0,
    wind_speed:   f.wind?.speed ?? null,
    wind_deg:     f.wind?.deg ?? null,
    weather_main: f.weather?.[0]?.main ?? null,
    weather_desc: f.weather?.[0]?.description ?? null,
    icon:         f.weather?.[0]?.icon ?? null,
  };
  if (ft.slice(0,10) === meta.target_date) day_forecasts.push(row);

  valueLines.push(
    `(${meta.lat_round}, ${meta.lon_round}, '${ft}'::timestamptz, `
    + `${num(row.temp)}, ${num(row.feels_like)}, ${num(row.humidity)}, `
    + `${num(row.pop)}, ${num(row.rain_3h)}, `
    + `${num(row.wind_speed)}, ${num(row.wind_deg)}, `
    + `${txt(row.weather_main)}, ${txt(row.weather_desc)}, ${txt(row.icon)}, `
    + `now())`
  );
}

// 用 CTE 包起 INSERT，最後 SELECT count → Postgres 節點剛好回 1 筆
// 否則 INSERT 不 RETURNING 會回 0 筆，下游節點不執行
const sql = valueLines.length === 0 ? null : `WITH ins AS (
  INSERT INTO weather_points (
    lat_round, lon_round, forecast_time,
    temp, feels_like, humidity,
    pop, rain_3h, wind_speed, wind_deg,
    weather_main, weather_desc, icon, fetched_at
  ) VALUES
${valueLines.join(',\n')}
  ON CONFLICT (lat_round, lon_round, forecast_time) DO UPDATE SET
    temp = EXCLUDED.temp,
    feels_like = EXCLUDED.feels_like,
    humidity = EXCLUDED.humidity,
    pop = EXCLUDED.pop,
    rain_3h = EXCLUDED.rain_3h,
    wind_speed = EXCLUDED.wind_speed,
    wind_deg = EXCLUDED.wind_deg,
    weather_main = EXCLUDED.weather_main,
    weather_desc = EXCLUDED.weather_desc,
    icon = EXCLUDED.icon,
    fetched_at = now()
  RETURNING 1
)
SELECT count(*) AS inserted FROM ins;`;

return [{ json: { sql, day_forecasts } }];

// 新抓資料：把當日的 forecasts 整理成 summary 與 cached 版本同 shape
const meta = $('Normalize Input').first().json;
const day = $('Flatten + Build Arrays').first().json.day_forecasts || [];

const pops   = day.map(r => Number(r.pop ?? 0));
const winds  = day.map(r => Number(r.wind_speed ?? 0));
const temps  = day.map(r => Number(r.temp ?? 0));
const feels  = day.map(r => Number(r.feels_like ?? 0));

const max_pop  = pops.length  ? Math.max(...pops)  : 0;
const max_wind = winds.length ? Math.max(...winds) : 0;
const max_temp = temps.length ? Math.max(...temps) : 0;
const min_temp = temps.length ? Math.min(...temps) : 0;
const max_feels= feels.length ? Math.max(...feels) : 0;
const avg_temp = temps.length ? +(temps.reduce((a,b)=>a+b,0) / temps.length).toFixed(1) : null;

const tags = [];
if (max_pop  >= 0.6) tags.push('heavy_rain_risk');
if (max_wind >= 10)  tags.push('strong_wind');
else if (max_wind >= 8) tags.push('windy');
if (max_temp >= 35)  tags.push('hot');
if (max_feels >= 38) tags.push('heat_stress');
if (min_temp <= 10)  tags.push('cold');

return [{
  json: {
    cached: false,
    event_id: meta.event_id,
    event_name: meta.event_name,
    lat_round: meta.lat_round,
    lon_round: meta.lon_round,
    date: meta.target_date,
    forecasts: day,
    summary: {
      slots: day.length,
      max_pop, max_wind, max_temp, min_temp, max_feels, avg_temp,
      alert_tags: tags,
    }
  }
}];
